#include <bits/stdc++.h>
using namespace std;

int n, m;
long long a[105], b[10005];
long long f[10005];

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        cin >> a[i];
    }
    for (int i = 0; i < n; i++) {
        cin >> b[i];
        f[i] = INT_MIN;
    }
    f[n] = INT_MIN;
    f[0] = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int tmp = (i + a[j] >= n) ? n : (i + a[j]);
            f[tmp] = max(f[tmp], f[i] + b[i]);
        }
    }
    cout << f[n];
    return 0;
}
